        "chi_s_p_64": "We receive by appointment only",
        "chi_s_h4_65": "Italy <span class=\"region-badge\">Headquarters</span>",
        "chi_s_p_66": "Our head office in Florence represents the center of excellence for specialized services in the equestrian sector. From here we coordinate all consultancy and support activities, guaranteeing in-depth expertise and customized solutions for every need of the equestrian world, both nationally and internationally.",
        "chi_s_h5_67": "Main services:",
        "chi_s_li_68": "Risk Management specialized for the equestrian sector",
        "chi_s_li_69": "Personalized insurance for horses and facilities",
        "chi_s_li_70": "Wealth Management dedicated to equestrian investments",
        "chi_s_li_71": "Specialist legal and financial consultancy",
        "chi_s_h4_72": "Europe <span class=\"region-badge\">European Partners</span>",
        "chi_s_p_73": "We are operational and provide specialized assistance in several European countries, guaranteeing complete support for equestrian activities through collaboration with qualified professionals in the sector. Our expertise extends to the different legislative and operational realities of the European equestrian landscape.",
        "chi_s_h5_74": "Main services:",
        "chi_s_li_75": "International risk management",
        "chi_s_li_76": "Specialized multilingual assistance",
        "chi_s_li_77": "Collaboration with local professionals",
        "chi_s_li_78": "Support for European equestrian activities",
        "chi_s_h4_79": "MENA <span class=\"region-badge\">International Partners</span>",
        "chi_s_p_80": "We are able to provide specialized legal and insurance services in the Middle East and North Africa areas, strategic regions with rapidly growing markets for the equestrian sector. Our expertise includes specialized linguistic support and in-depth knowledge of local regulatory and cultural peculiarities.",
        "chi_s_h5_81": "Main services:",
        "chi_s_li_82": "Professional support in Arabic",
