        "fin_p_14": "Current account at more advantageous costs for individuals associated with entities adhering to the agreement.",
        "fin_li_15": "Banking operations at preferential conditions",
        "fin_li_16": "Reduced annual fee",
        "fin_li_17": "Dedicated digital services",
        "fin_li_18": "Debit and credit cards at advantageous conditions",
        "fin_h4_19": "INVESTMENT SECURITIES",
        "fin_p_20": "Contract with which the beneficiary will be guaranteed a payment agreed with the debtor, should the latter fail to pay what was originally agreed.",
        "fin_p_21": "Sureties (contract with which the insurance company guarantees the payment of fees for the properties where the amateur sports insurance carries out its activities).",
        "fin_li_22": "Guarantees for rental contracts",
        "fin_li_23": "Deposits for participation in competitions",
        "fin_li_24": "Sureties for sports facilities",
        "fin_li_25": "Roofing for temporary structures",
        "fin_h4_26": "INVESTMENTS",
        "fin_p_27": "Customized investment solutions for operators in the equestrian sector, with a focus on sustainable growth and capital protection.",
        "fin_li_28": "Personalized investment plans",
        "fin_li_29": "Solutions for risk diversification",
