/**
 * Funzione per il cambio lingua
 */
function changeLanguage(lang) {
    if (!translations[lang]) return;

    // Salva la preferenza in localStorage
    localStorage.setItem('preferredLanguage', lang);

    // Cambia il testo nel nav dropdown
    const dropdown = document.getElementById('languageDropdown');
    if (dropdown) {
        dropdown.innerText = lang.toUpperCase();
    }

    // Trova tutti gli elementi con l'attributo data-i18n
    const elements = document.querySelectorAll('[data-i18n]');

    elements.forEach(element => {
        const key = element.getAttribute('data-i18n');
        // Se la traduzione esiste, applicala
        if (translations[lang][key]) {
            element.innerHTML = translations[lang][key];
        }
    });

    // Aggiorna attributo lang del tag HTML
    document.documentElement.lang = lang;
}

// Inizializza lingua all'avvio
document.addEventListener('DOMContentLoaded', () => {
    // Leggi preferenza o default a italiano
    const savedLang = localStorage.getItem('preferredLanguage') || 'it';
    changeLanguage(savedLang);

    // Setup listener per i bottoni/link lingua
    const langLinks = document.querySelectorAll('[data-lang-switch]');
    langLinks.forEach(link => {
        link.addEventListener('click', (e) => {
            e.preventDefault();
            const newLang = link.getAttribute('data-lang-switch');
            changeLanguage(newLang);
        });
    });

    // Imposta la classe active sulla navbar in base alla pagina corrente
    const currentPath = window.location.pathname.split('/').pop() || 'index.html';
    document.querySelectorAll('.navbar-nav .nav-link').forEach(link => {
        const linkPath = link.getAttribute('href');
        if (linkPath === currentPath || (currentPath === '' && linkPath === 'index.html')) {
            link.classList.add('active');
        } else {
            link.classList.remove('active');
        }
    });
});
